/// clear BSS segment
fn clear_bss() {
    extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        ptr::write_bytes(sbss as *mut c_void, 0, ebss as usize - sbss as usize);
    }
}

#[no_mangle]
pub fn fake_main(hart_id: usize) {
    #[cfg(target_arch = "riscv64")]
    unsafe {
        asm!("add sp, sp, {}", in(reg) KERNEL_BASE);
        asm!("la t0, rust_main");
        asm!("add t0, t0, {}", in(reg) KERNEL_BASE);
        asm!("mv a0, {}", in(reg) hart_id);
        asm!("jalr zero, 0(t0)");
    }
    #[cfg(target_arch = "loongarch64")]
    unsafe {
        asm!("la.global $t0, rust_main");
        asm!("move $a0, {}", in(reg) hart_id);
        asm!("jirl $zero, $t0, 0");
    }
}

#[allow(unused)]
static DEBUG_FLAG: AtomicU8 = AtomicU8::new(0);

#[no_mangle]
pub fn rust_main(_hart_id: usize) -> ! {
    clear_bss();
    println!("hello world");
    logging::init();
    mm::init();
    trap::init();
    // 允许S mode访问U mode的页面
    //  S mode下会访问User的堆
    crate::arch::activate_user_memory_access();
    #[cfg(feature = "test")]
    {
        logging::test();
        trap::context::trap_cx_test();
    }
    show_context_size();
    trap::enable_timer_interrupt();
    timer::set_next_trigger();
    log::info!("before add_initproc");
    add_initproc();
    log::info!("after add_initproc");
    let root_dentry = INITPROC.root().dentry.clone();
    log::info!("got initproc root");
    init_devfs(root_dentry);
    log::info!("after init_devfs");
    loader::list_apps();
    // pass block_device_test, 注意实际运行时别调用这个函数, 会覆盖Block内容
    DEBUG_FLAG.store(1, core::sync::atomic::Ordering::SeqCst);
    log::info!("before run_tasks");
    run_tasks();
    panic!("shutdown machine");
}

pub fn show_context_size() {
    log::info!(
        "size of trap context: {}",
        core::mem::size_of::<TrapContext>()
    );
    log::info!(
        "size of task context: {}",
        core::mem::size_of::<TaskContext>()
    )
}

