    exited_usage: SpinNoIrqLock<Option<ResourceUsage>>, // 退出时冻结的自身资源用量
    children_usage: Arc<SpinNoIrqLock<ResourceUsage>>, // 已 wait 回收子进程资源累计
    last_scheduled_at: AtomicU64,   // 最近一次被调度运行的时间戳
    last_enqueued_at: AtomicU64,    // 最近一次进入 ready 队列的时间戳
    schedule_count: AtomicU64,      // 被调度运行的次数
    run_ticks: AtomicU64,           // 粗粒度累计运行 ticks
    sched_policy: AtomicI32,        // 调度策略: SCHED_OTHER=0, SCHED_FIFO=1, SCHED_RR=2
