impl core::fmt::Debug for Task {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        f.debug_struct("Task")
            .field("tid", &self.tid())
            .field("tgid", &self.tgid())
            .finish()
    }
}

/// 全局存活任务计数 (Arc<Task> 创建时 +1, Drop 时 -1)
pub static TASK_LIVE_COUNT: AtomicUsize = AtomicUsize::new(0);
static TASK_CREATE_TOTAL: AtomicUsize = AtomicUsize::new(0);
static TASK_DROP_TOTAL: AtomicUsize = AtomicUsize::new(0);
static TASK_PEAK_LIVE: AtomicUsize = AtomicUsize::new(0);

fn update_peak(peak: &AtomicUsize, value: usize) {
    let mut old = peak.load(Ordering::Relaxed);
    while value > old {
        match peak.compare_exchange_weak(old, value, Ordering::Relaxed, Ordering::Relaxed) {
            Ok(_) => break,
            Err(next) => old = next,
        }
    }
}

pub(super) fn record_task_created() {
    TASK_CREATE_TOTAL.fetch_add(1, Ordering::Relaxed);
    let live = TASK_LIVE_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
    update_peak(&TASK_PEAK_LIVE, live);
}

pub fn task_lifecycle_stats() -> (usize, usize, usize, usize) {
    (
        TASK_CREATE_TOTAL.load(Ordering::Relaxed),
        TASK_DROP_TOTAL.load(Ordering::Relaxed),
        TASK_LIVE_COUNT.load(Ordering::Relaxed),
        TASK_PEAK_LIVE.load(Ordering::Relaxed),
