fn shared_file_frame(file: &Arc<dyn FileOp>, file_offset: usize) -> Option<Arc<FrameTracker>> {
    let file = file.as_any().downcast_ref::<crate::fs::file::File>()?;
    let path = file.inner_handler(|inner| inner.path.dentry.absolute_path.clone());
    let key = (path, file_offset);

    if let Some(frame) = FILE_SHARED_FRAMES.lock().get(&key).cloned() {
        if key.0.contains("ltp_execveat01") {
            log::error!(
                "[execveat01-debug] shared_file_frame hit path={} off={:#x} ppn={:#x}",
                key.0,
                key.1,
                frame.ppn.0
            );
        }
        return Some(frame);
    }

    let frame = frame_alloc()?;
    let dst = frame.ppn.get_bytes_array();
    let old_offset = file.get_offset();
    file.seek(file_offset);
    let _ = file.read(dst);
    file.seek(old_offset);
    let frame = Arc::new(frame);
    if key.0.contains("ltp_execveat01") {
        log::error!(
            "[execveat01-debug] shared_file_frame new path={} off={:#x} ppn={:#x}",
            key.0,
            key.1,
            frame.ppn.0
        );
    }
    FILE_SHARED_FRAMES.lock().insert(key, frame.clone());
    Some(frame)
}

