fn read_user_insn_word(pa: usize) -> Option<u32> {
    #[cfg(target_arch = "riscv64")]
    const MEMORY_START: usize = 0x8000_0000;
    #[cfg(target_arch = "loongarch64")]
    const MEMORY_START: usize = 0x0;

    let end = pa.checked_add(core::mem::size_of::<u32>())?;
    if pa < MEMORY_START || end > crate::boards::qemu::MEMORY_END {
        return None;
    }
    let kva = pa.checked_add(crate::config::KERNEL_BASE)?;
    Some(unsafe { core::ptr::read_unaligned(kva as *const u32) })
}

fn read_user_fault_window(task: &crate::task::Task, sepc: usize) -> [u8; 16] {
    let mut out = [0u8; 16];
    let start = sepc.saturating_sub(8);
    task.op_memory_set(|m| {
        for (i, byte) in out.iter_mut().enumerate() {
            let va = crate::mm::VirtAddr::from(start + i);
            if let Some(pa) = m.page_table.translate_va_to_pa(va) {
                #[cfg(target_arch = "riscv64")]
                const MEMORY_START: usize = 0x8000_0000;
                #[cfg(target_arch = "loongarch64")]
                const MEMORY_START: usize = 0x0;
                if pa >= MEMORY_START && pa < crate::boards::qemu::MEMORY_END {
                    let kva = pa + crate::config::KERNEL_BASE;
                    *byte = unsafe { core::ptr::read_unaligned(kva as *const u8) };
                }
            }
        }
    });
    out
}

fn describe_user_pte(task: &crate::task::Task, va: usize) -> alloc::string::String {
    task.op_memory_set(|m| {
        let vpn = crate::mm::VirtAddr::from(va).floor();
        m.page_table
            .translate_vpn_to_pte(vpn)
            .map(|pte| alloc::format!("va={:#x} vpn={:#x} {:?}", va, vpn.0, pte))
            .unwrap_or_else(|| alloc::format!("va={:#x} vpn={:#x} <none>", va, vpn.0))
    })
}

fn describe_user_mapping(task: &crate::task::Task, va: usize) -> alloc::string::String {
    task.op_memory_set(|m| m.debug_user_va_mapping(va))
}

fn read_elf_fault_window(exe: &str, sepc: usize) -> Option<(usize, [u8; 16])> {
    let file = path_openat(exe, 0, crate::fs::AT_FDCWD, 0).ok()?;
    let data = file.read_all();
    let elf = xmas_elf::ElfFile::new(data.as_slice()).ok()?;
    for i in 0..elf.header.pt2.ph_count() {
        let ph = elf.program_header(i).ok()?;
        if ph.get_type().ok()? != Type::Load {
            continue;
        }
        let vaddr = ph.virtual_addr() as usize;
        let file_size = ph.file_size() as usize;
        let mem_size = ph.mem_size() as usize;
        if sepc < vaddr || sepc >= vaddr.saturating_add(mem_size) {
            continue;
        }
        let delta = sepc - vaddr;
        if delta >= file_size {
            return None;
        }
        let file_center = ph.offset() as usize + delta;
        let file_start = file_center.saturating_sub(8);
        let mut out = [0u8; 16];
        for (idx, byte) in out.iter_mut().enumerate() {
            if let Some(src) = data.get(file_start + idx) {
                *byte = *src;
            }
        }
        return Some((file_start, out));
    }
    None
}

fn dump_user_fault_context(kind: &str, cx: &TrapContext, fault_addr: usize) {
    let task = crate::task::current_task();
    let (sid, a0, a1, a2, a3) = task.last_syscall_snapshot();
    let (insn, pte) = task.op_memory_set(|m| {
        let va = crate::mm::VirtAddr::from(cx.sepc);
        let pte = m
            .page_table
            .translate_vpn_to_pte(va.floor())
            .map(|pte| alloc::format!("{:?}", pte))
            .unwrap_or_else(|| alloc::format!("<none>"));
        let insn = m
            .page_table
            .translate_va_to_pa(va)
            .and_then(read_user_insn_word)
            .unwrap_or(0);
        (insn, pte)
    });
    let exe = task.exe_path_string();
    let mem_window = read_user_fault_window(&task, cx.sepc);
    let mut candidate_bytes = [0u8; core::mem::size_of::<usize>()];
    candidate_bytes.copy_from_slice(&mem_window[4..4 + core::mem::size_of::<usize>()]);
    let candidate_va = usize::from_le_bytes(candidate_bytes);
    let sepc_pte = describe_user_pte(&task, cx.sepc);
    let sp_pte = describe_user_pte(&task, cx.x[2]);
    let candidate_pte = describe_user_pte(&task, candidate_va);
    let candidate_slot = candidate_va.saturating_sub(core::mem::size_of::<usize>());
    let candidate_slot_mapping = describe_user_mapping(&task, candidate_slot);
    let elf_window = read_elf_fault_window(&exe, cx.sepc);
    log::error!(
        "[{}] tid {}, exe {}, fault {:#x}, sepc {:#x}, insn {:#010x}, pte {}, sp {:#x}, ra {:#x}, arg0 {:#x}, last_syscall {} a0 {:#x} a1 {:#x} a2 {:#x} a3 {:#x}, mem@{:#x}={:02x?}, elf={}, sepc_pte={}, sp_pte={}, candidate={:#x} candidate_pte={}, candidate_slot={}",
        kind,
        task.tid(),
        exe,
        fault_addr,
        cx.sepc,
        insn,
        pte,
        cx.x[crate::arch::USER_STACK_POINTER_REG],
        cx.x[crate::arch::USER_RETURN_REG],
        cx.x[crate::arch::SYSCALL_ARG0_REG],
        sid,
        a0,
        a1,
        a2,
        a3,
        cx.sepc.saturating_sub(8),
        mem_window,
        elf_window
            .map(|(off, bytes)| alloc::format!("off {:#x} {:02x?}", off, bytes))
            .unwrap_or_else(|| alloc::format!("<none>")),
        sepc_pte,
        sp_pte,
        candidate_va,
        candidate_pte,
        candidate_slot_mapping
    );
}

fn deliver_sync_signal(signum: usize, cx: &mut TrapContext, reason: &str, fault_addr: usize) {
    let task = crate::task::current_task();
    let action = task.signal_get_action_copy(signum);
    if action.sa_handler == crate::signal::SIG_DFL {
        log::error!(
            "[trap] {}: tid {} exe {} addr {:#x} sepc {:#x}; default sig {} action",
            reason,
            task.tid(),
            task.exe_path_string(),
            fault_addr,
            cx.sepc,
            signum
        );
    }
    let _ = send_signal(&task, signum);
    check_pending_signals(&task, cx);
}

fn check_current_real_timer_signal(cx: &mut TrapContext) -> bool {
    let task = crate::task::current_task();
    task.check_real_itimer(crate::timer::get_time_ms() as u64);
    check_pending_signals(&task, cx)
}

