fn terminate_remote_task_by_signal(target: &Arc<Task>, signum: usize, dumped_core: bool) {
    let signal_status = if signum <= 0x7f {
        signum as i32
    } else {
        (signum & 0x7f) as i32
    };
    let signal_status = if dumped_core {
        signal_status | 0x80
    } else {
        signal_status
    };
    let exit_code = -signal_status;
    let tid = target.tid();
    kernel_exit_group(target.clone(), exit_code);
    remove_task(tid);
}

/// 向目标任务发送信号
///
/// 设置 pending 位, 如果目标处于可中断睡眠则唤醒之。
/// 返回 0 成功, 负数 errno。
pub fn send_signal(target: &Arc<Task>, signum: usize) -> isize {
    if signum == 0 || signum >= NSIG {
        return -22; // EINVAL
    }

    // 进程已退出 (僵尸)
    if target.is_zombie() {
        return -3; // ESRCH
    }

    let current_tid = crate::task::current_task().tid();
    if signum == super::SIGKILL && target.tid() != current_tid {
        terminate_remote_task_by_signal(target, signum, false);
        return 0;
    }
    if signum == super::SIGCONT {
        if target.is_stopped() {
            target.set_continued_event();
            target.clear_wait();
            wake_specific_task(target);
            if let Some(parent) = target.op_parent(|p| p.as_ref().and_then(|w| w.upgrade())) {
                parent.notify_child_exit();
                let _ = send_signal(&parent, super::SIGCHLD);
                crate::task::wake_waiters_for_child(parent.tid(), target.tid());
            }
        } else {
            target.clear_stopped_state();
        }
    }

    // 设置 pending 位
    target.signal_add_pending(signum);
    let target_exe = target.exe_path_string();
    if trace_libctest(&target_exe) || trace_libctest(&crate::task::current_task().exe_path_string()) {
        let (pending, blocked) = target.signal_get_pending_blocked();
        log::debug!(
            "[signal-send] from tid {} exe {} -> tid {} exe {} sig {} pending {:#x} blocked {:#x}",
            crate::task::current_task().tid(),
            crate::task::current_task().exe_path_string(),
            target.tid(),
            target_exe,
            signum,
            pending.bits,
            blocked.bits
        );
    }

    // 如果目标是其他任务且在可中断阻塞等待中，并且该信号当前未被阻塞，
    // 唤醒它让 syscall 返回 EINTR。被 sigmask 屏蔽的信号保持 pending，
    // 不应打断 epoll_pwait/ppoll/pselect 这类带临时 mask 的等待。
    let should_interrupt_sleep = {
        let action = target.signal_get_action_copy(signum);
        let (_, blocked) = target.signal_get_pending_blocked();
        !blocked.contains(signum)
            && action.sa_handler != super::SIG_IGN
            && !(action.sa_handler == super::SIG_DFL
                && matches!(
                    super::sigaction::default_action(signum),
                    super::sigaction::DefaultAction::Ignore | super::sigaction::DefaultAction::Cont
                ))
    };
    if target.tid() != current_tid && should_interrupt_sleep {
        crate::task::wake_blocked_task_for_signal(target.tid());
    }

    0
}

pub fn send_signal_with_info(target: &Arc<Task>, signum: usize, info: SigInfo) -> isize {
    if signum == 0 || signum >= NSIG {
        return -22;
    }
    if target.is_zombie() {
        return -3;
    }
    target.signal_add_pending_with_info(signum, info);
    if trace_libctest(&target.exe_path_string()) && signum == 33 {
        let (pending, blocked) = target.signal_get_pending_blocked();
        log::debug!(
            "[signal-send-info] tid {} sig {} pending {:#x} blocked {:#x} info_count {}",
            target.tid(),
            signum,
            pending.bits,
            blocked.bits,
            target.signal_info_count(signum)
        );
    }
    let should_interrupt_sleep = {
        let action = target.signal_get_action_copy(signum);
        let (_, blocked) = target.signal_get_pending_blocked();
        !blocked.contains(signum)
            && action.sa_handler != super::SIG_IGN
            && !(action.sa_handler == super::SIG_DFL
                && matches!(
                    super::sigaction::default_action(signum),
                    super::sigaction::DefaultAction::Ignore | super::sigaction::DefaultAction::Cont
                ))
    };
    if target.tid() != crate::task::current_task().tid() && should_interrupt_sleep {
        crate::task::wake_blocked_task_for_signal(target.tid());
