                    .iter()
                    .find(|task| task.tid() == tid)
                    .cloned()
            })
    }

    pub fn wake_waiters_for_child(&mut self, parent_tid: Tid, child_tid: Tid) {
        let mut idx = 0usize;
        while idx < self.blocked_queue.len() {
            let wake = {
                let task = &self.blocked_queue[idx];
                task.tid() == parent_tid
                    && matches!(task.wait_kind(), WaitKind::Child { pid }
                        if child_wait_matches(task, pid, child_tid))
            };
            if wake {
                if let Some(task) = self.blocked_queue.remove(idx) {
                    task.finish_child_wait();
                    task.set_ready();
                    self.add(task);
                    continue;
                }
            }
            idx += 1;
        }

        // 与 futex 类似，父进程可能在 arm_child_wait_target(pid) 之后、
        // blocking_and_run_next() 之前被时钟中断 yield 到 ready_queue。
        // 若子进程此时退出，只扫描 blocked_queue 会漏掉它，随后父进程
        // 重新运行后才真正 block，形成“已退出子进程却无人唤醒”的卡住现象。
        for task in self.ready_queue.iter() {
            let wake = task.tid() == parent_tid
                && matches!(task.wait_kind(), WaitKind::Child { pid }
                    if child_wait_matches(task, pid, child_tid));
            if wake {
                task.finish_child_wait();
            }
        }
    }

    pub fn wake_waiters_for_futex_bitset(
        &mut self,
        uaddr: usize,
        bitset: u32,
        max_wake: usize,
    ) -> usize {
        let mut woken = 0usize;

        // 1) 扫描 blocked_queue：找到等待该 futex 的任务，移回 ready_queue
        let mut idx = 0usize;
        while idx < self.blocked_queue.len() && woken < max_wake {
            let wake = {
                let task = &self.blocked_queue[idx];
                matches!(task.wait_kind(), WaitKind::Futex { waiter } if waiter.matches(uaddr, bitset))
            };
            if wake {
                if let Some(task) = self.blocked_queue.remove(idx) {
                    task.finish_futex_wait();
                    task.set_ready();
                    self.add(task);
                    woken += 1;
                    continue;
                }
            }
            idx += 1;
        }

        // 2) 扫描 ready_queue：任务可能在 set_waiting_for_futex 之后、
        //    blocking_and_run_next 之前被定时器中断 yield 到了 ready_queue。
        //    此时只需清除其 waiting_for_futex，它被调度时会自行发现 futex 值已变。
        for task in self.ready_queue.iter() {
            if woken >= max_wake {
                break;
            }
            if matches!(task.wait_kind(), WaitKind::Futex { waiter } if waiter.matches(uaddr, bitset)) {
                task.finish_futex_wait();
                woken += 1;
            }
        }

        woken
    }

    pub fn requeue_waiters_for_futex(
        &mut self,
        from: usize,
        to: usize,
        bitset: u32,
        max_wake: usize,
        max_requeue: usize,
    ) -> usize {
        let mut moved = 0usize;
        let mut woken = 0usize;

        let mut idx = 0usize;
        while idx < self.blocked_queue.len() && (woken < max_wake || moved < max_requeue) {
            let action = {
                let task = &self.blocked_queue[idx];
                task.futex_waiter()
                    .filter(|waiter| waiter.matches(from, bitset))
                    .map(|_| if woken < max_wake { 0 } else { 1 })
            };
            match action {
                Some(0) => {
                    if let Some(task) = self.blocked_queue.remove(idx) {
                        task.finish_futex_wait();
                        task.set_ready();
                        self.add(task);
                        woken += 1;
                        continue;
                    }
                }
                Some(1) => {
                    if let Some(task) = self.blocked_queue.get(idx) {
                        let new_waiter = task
                            .futex_waiter()
                            .map(|waiter| FutexWaiter::new(to, waiter.bitset))
                            .unwrap_or(FutexWaiter::new(to, bitset));
                        task.retarget_futex_wait(new_waiter);
                        moved += 1;
                    }
                }
                _ => {}
            }
            idx += 1;
        }

        for task in self.ready_queue.iter() {
            if woken >= max_wake && moved >= max_requeue {
