pub trait InodeOp: Any + Send + Sync {
    // 主要用来获得在disk上的结构
    fn as_any(&self) -> &dyn Any;
    // 用于文件读写
    fn read<'a>(&'a self, offset: usize, buf: &'a mut [u8]) -> usize;
    fn write<'a>(&'a self, page_offset: usize, buf: &'a [u8]) -> usize;
