    // 注意: 这里可能返回负目录项
    // 上层调用者保证:
    //      1. 先查找dentry cache, 如果没有再查找目录
    //      3. 上层调用者保证将dentry放进dentry cache中
    fn lookup<'a>(&'a self, name: &str, parent_dentry: Arc<Dentry>) -> Arc<Dentry>;
    // self是目录inode, name是新建文件的名字, mode是新建文件的类型
    // fn mknod<'a>(&'a self, name: &str, mode: u16) -> Arc<Dentry>;
    // self是目录, Dentry是上层根据文件名新建的负目录项(已经建立了父子关系)
    // 上层调用者保证:
    //      1. 创建的文件名在目录中不存在
    //      2. Dentry的inode字段为None(负目录项)
    fn create<'a>(&'a self, negative_dentry: Arc<Dentry>, mode: u16, uid: u32, gid: u32);
    fn mknod<'a>(&'a self, _negative_dentry: Arc<Dentry>, _mode: u16, _dev: u32) -> Result<(), isize> {
        Err(-1)
    }
    fn symlink<'a>(&'a self, negative_dentry: Arc<Dentry>, target: &str);
    // self是目录inode, old_dentry是旧的目录项, new_dentry是新的目录项, 他们指向同一个inode
    fn link<'a>(&'a self, old_dentry: Arc<Dentry>, new_dentry: Arc<Dentry>);
    // 上层调用者保证:
    //     1. 在unlink调用后, inode的dentry cache中中对应的dentry无效化(变为负目录项)
    //     2. 仅有已有`File`可以访问inode
    fn unlink<'a>(&'a self, dentry: Arc<Dentry>);
    // 创建临时文件, 用于临时文件系统, inode没有对应的路径, 不会分配目录项
    // 临时文件没有对应的目录项, 只能通过fd进行访问
    // 与create的唯一区别是: 1. 没有对应的目录项
    fn tmpfile<'a>(&'a self, mode: u16) -> Arc<Ext4Inode>;
    fn mkdir<'a>(&'a self, dentry: Arc<Dentry>, mode: u16);
    /// chmod(2)/fchmodat(2): 更新权限位与 suid/sgid/sticky 位，保留文件类型位。
    fn chmod(&self, mode: u16) -> Result<(), isize>;
    /// chown(2)/fchownat(2): 更新属主/属组，None 表示对应字段不变。
    fn chown(&self, uid: Option<u32>, gid: Option<u32>) -> Result<(), isize>;
    // 检查是否是目录, 且有子目录项可以用于lookup
    fn can_lookup(&self) -> bool;
    /// Return symlink target bytes when this inode is a symbolic link.
    fn readlink(&self) -> Option<Vec<u8>> {
        None
    }
    // 上层readdir调用
    fn getdents(&self) -> Vec<LinuxDirent64>;
    fn getdents_at(&self, start_off: usize, max_bytes: usize) -> Vec<LinuxDirent64> {
        let mut used = 0usize;
        self.getdents()
            .into_iter()
            .filter(|dirent| dirent.d_off as usize > start_off)
            .take_while(|dirent| {
                let reclen = dirent.d_reclen as usize;
                if used + reclen > max_bytes {
                    return false;
                }
                used += reclen;
                true
            })
            .collect()
    }
    fn getattr(&self) -> Kstat;
    fn get_inode_num(&self) -> usize;
}

