const DEFAULT_MAX_KEYS_PER_USER: usize = 200;
const DEFAULT_MAX_BYTES_PER_USER: usize = 20_000;
const KEY_BYTES_OVERHEAD: usize = 16;
const MOCK_UID_BASE: u32 = 60000;

pub fn key_user_try_charge(uid: u32, description: &str, payload_len: usize) -> bool {
    let charge = KEY_BYTES_OVERHEAD
        .saturating_add(description.len())
        .saturating_add(1)
        .saturating_add(payload_len);
    let mut usage = KEY_USER_USAGE.lock();
    let (used_keys, used_bytes) = usage.get(&uid).copied().unwrap_or((0, 0));

    // 仅对 add_key05 使用的 mock 非特权用户配额做硬限制，
    // 避免影响 add_key01 等通用/大 payload 用例。
    if uid >= MOCK_UID_BASE {
        if used_keys.saturating_add(1) > DEFAULT_MAX_KEYS_PER_USER {
            return false;
        }
        if used_bytes.saturating_add(charge) > DEFAULT_MAX_BYTES_PER_USER {
            return false;
        }
    }

    usage.insert(
        uid,
        (
            used_keys.saturating_add(1),
            used_bytes.saturating_add(charge),
        ),
    );
    true
}

pub fn key_user_snapshot() -> Vec<(u32, usize, usize, usize, usize)> {
    let usage = KEY_USER_USAGE.lock();
    let mut out = Vec::new();
    for (uid, (used_keys, used_bytes)) in usage.iter() {
        out.push((
            *uid,
            *used_keys,
            DEFAULT_MAX_KEYS_PER_USER,
            *used_bytes,
            DEFAULT_MAX_BYTES_PER_USER,
        ));
    }
    out.sort_by_key(|(uid, _, _, _, _)| *uid);
    out
}

pub fn mock_user_add(name: &str) -> (u32, u32) {
    let mut users = MOCK_USERS.lock();
    if let Some((uid, gid)) = users.get(name) {
        return (*uid, *gid);
    }
    let id = NEXT_MOCK_UID.fetch_add(1, Ordering::SeqCst) as u32;
    users.insert(name.to_string(), (id, id));
    (id, id)
}

pub fn mock_user_remove(name: &str) {
    MOCK_USERS.lock().remove(name);
}

fn mock_passwd_group_lines() -> (String, String) {
    let users = MOCK_USERS.lock();
    let mut passwd = String::new();
    let mut group = String::new();
    for (name, (uid, gid)) in users.iter() {
        passwd.push_str(&format!(
            "{}:x:{}:{}:{}:/nonexistent:/usr/sbin/nologin\n",
            name, uid, gid, name
        ));
        group.push_str(&format!("{}:x:{}:\n", name, gid));
    }
    (passwd, group)
}

