// Linux pipes are typically provisioned with 16 pages by default.  Keep one
// extra internal byte so the ring buffer can still distinguish full from empty.
const PIPE_DEFAULT_CAPACITY: usize = 16 * 4096;
const PIPE_BUFFER_SIZE: usize = PIPE_DEFAULT_CAPACITY + 1;
const PIPE_BUF: usize = 4096;
pub const PIPE_MAX_SIZE: usize = 1 << 20;
pub const PIPE_DEFAULT_SIZE: usize = PIPE_DEFAULT_CAPACITY;
pub const PIPE_POLL_WAKE_KEY: usize = 0xfeed_f00d_f00d_0000;
static NEXT_PIPE_WAKE_KEY: AtomicUsize = AtomicUsize::new(0xfeed_0000_0000_0000);

lazy_static! {
    static ref FIFO_BUFFERS: SpinNoIrqLock<BTreeMap<usize, FifoState>> =
        SpinNoIrqLock::new(BTreeMap::new());
}

#[derive(Clone)]
struct FifoState {
    buffer: Arc<SpinNoIrqLock<PipeRingBuffer>>,
    read_wake_key: usize,
    write_wake_key: usize,
}

fn has_interrupting_signal() -> bool {
    let task = current_task();
    let (pending, blocked) = task.signal_get_pending_blocked();
    let Some(signum) = pending.first_unblocked(&blocked) else {
        return false;
    };
    let action = task.signal_get_action_copy(signum);
    if action.sa_handler == SIG_IGN {
        return false;
    }
    if action.sa_handler == SIG_DFL
        && matches!(default_action(signum), DefaultAction::Ignore | DefaultAction::Cont)
    {
        return false;
    }
    true
}

pub struct Pipe {
    buffer: Arc<SpinNoIrqLock<PipeRingBuffer>>,
    readable: bool,
    writeable: bool,
    flags: SpinNoIrqLock<usize>,
    capacity: AtomicUsize,
    read_wake_key: usize,
    write_wake_key: usize,
}

impl Pipe {
    pub const WRITE_EPIPE: usize = usize::MAX;
    pub const WRITE_EAGAIN: usize = usize::MAX - 1;
    fn initial_capacity() -> usize {
        let default_size = PIPE_DEFAULT_SIZE;
        let sysctl_max = crate::fs::procfs::fs_pipe_max_size_sysctl();
        let task = current_task();
        if (task.cap_effective() & (1u64 << 24)) != 0 {
            default_size
        } else {
            default_size.min(sysctl_max).max(PIPE_BUF)
        }
    }

    /// return (pipe_read, pipe_write)
    pub fn new_pair() -> (Arc<Self>, Arc<Self>) {
        Self::new_pair_with_packet_mode(false)
    }

    pub fn new_pair_with_packet_mode(packet_mode: bool) -> (Arc<Self>, Arc<Self>) {
        let buffer = Arc::new(SpinNoIrqLock::new(PipeRingBuffer {
            buffer: alloc::vec![0u8; PIPE_BUFFER_SIZE].into_boxed_slice(),
            read_pos: 0,
            write_pos: 0,
            eof: false,
            writer_refs: 0,
            reader_refs: 0,
            reader_has_opened: false,
            packet_mode,
            packet_lengths: VecDeque::new(),
            buffered_bytes: 0,
        }));
        let read_wake_key = NEXT_PIPE_WAKE_KEY.fetch_add(2, Ordering::Relaxed);
        let write_wake_key = read_wake_key + 1;
        let capacity = Self::initial_capacity();
        (
            Arc::new(Self {
                buffer: buffer.clone(),
                readable: true,
                writeable: false,
                flags: SpinNoIrqLock::new(0),
                capacity: AtomicUsize::new(capacity),
                read_wake_key,
                write_wake_key,
            }),
            Arc::new(Self {
                buffer: buffer.clone(),
                readable: false,
                writeable: true,
                flags: SpinNoIrqLock::new(0),
                capacity: AtomicUsize::new(capacity),
                read_wake_key,
                write_wake_key,
            }),
        )
    }

    pub fn new_fifo(inode_num: usize, flags: usize) -> Arc<Self> {
        let state = {
            let mut fifos = FIFO_BUFFERS.lock();
            fifos
                .entry(inode_num)
                .or_insert_with(|| {
                    let read_wake_key = NEXT_PIPE_WAKE_KEY.fetch_add(2, Ordering::Relaxed);
                    FifoState {
                        buffer: Arc::new(SpinNoIrqLock::new(PipeRingBuffer {
                            buffer: alloc::vec![0u8; PIPE_BUFFER_SIZE].into_boxed_slice(),
                            read_pos: 0,
                            write_pos: 0,
                            eof: true,
                            writer_refs: 0,
                            reader_refs: 0,
                            reader_has_opened: false,
                            packet_mode: false,
                            packet_lengths: VecDeque::new(),
                            buffered_bytes: 0,
                        })),
                        read_wake_key,
                        write_wake_key: read_wake_key + 1,
                    }
                })
                .clone()
        };
        let accmode = flags & 0b11;
        let capacity = Self::initial_capacity();

