    mount_table: Vec<Arc<Mount>>,
    records: Vec<MountRecord>,
    next_id: MountId,
    next_group: GroupId,
    next_event: EventId,
}

impl MountTree {
    fn new() -> Self {
        MountTree {
            mount_table: Vec::new(),
            records: Vec::new(),
            next_id: 1,
            next_group: 1,
            next_event: 1,
        }
    }

    fn alloc_id(&mut self) -> MountId {
        let id = self.next_id;
        self.next_id += 1;
        id
    }

    fn alloc_group(&mut self) -> GroupId {
        let group = self.next_group;
        self.next_group += 1;
        group
    }

    fn alloc_event(&mut self) -> EventId {
        let event = self.next_event;
        self.next_event += 1;
        event
    }

    fn top_index_at(&self, path: &str) -> Option<usize> {
        let path = normalize_mount_path(path);
