#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Trap {
    Syscall,
    Timer,
    LoadPageFault,
    StorePageFault,
    InstructionPageFault,
    AddressError,
    LoadPermissionFault,
    StorePermissionFault,
    InstructionPermissionFault,
    Breakpoint,
    IllegalInstruction,
    Unknown,
}

pub fn activate_user_memory_access() {
    unsafe {
        sstatus::set_sum();
    }
}

pub fn initial_user_status() -> usize {
    let mut status = sstatus::read();
    status.set_spp(riscv::register::sstatus::SPP::User);
    // On sret, SIE is restored from SPIE. User-mode contexts must therefore
    // carry SPIE=1, otherwise timer interrupts stay disabled after returning
    // from freshly built contexts such as rt_sigreturn.
    let mut bits = status.bits();
    const SSTATUS_SIE: usize = 1 << 1;
    const SSTATUS_SPIE: usize = 1 << 5;
    bits &= !SSTATUS_SIE;
    bits |= SSTATUS_SPIE;
    bits
}

pub fn init_trap_entry(_user_entry: usize, kernel_entry: usize) {
    let mut status = sstatus::read();
    status.set_spp(riscv::register::sstatus::SPP::Supervisor);
    unsafe {
        stvec::write(kernel_entry, stvec::TrapMode::Direct);
    }
}

