}

pub fn trap_cause() -> Trap {
    match scause::read().cause() {
        scause::Trap::Exception(Exception::UserEnvCall) => Trap::Syscall,
        scause::Trap::Interrupt(Interrupt::SupervisorTimer) => Trap::Timer,
        scause::Trap::Exception(Exception::StorePageFault)
        | scause::Trap::Exception(Exception::StoreFault) => Trap::StorePageFault,
        scause::Trap::Exception(Exception::LoadPageFault)
        | scause::Trap::Exception(Exception::LoadFault) => Trap::LoadPageFault,
        scause::Trap::Exception(Exception::InstructionPageFault) => Trap::InstructionPageFault,
        scause::Trap::Exception(Exception::Breakpoint) => Trap::Breakpoint,
        scause::Trap::Exception(Exception::IllegalInstruction) => Trap::IllegalInstruction,
        _ => Trap::Unknown,
    }
}

