bitflags! {
    #[derive(Clone, Copy)]
    pub struct PTEFlags: u16 {
        const V = 1 << 0;
        const R = 1 << 1;
        const W = 1 << 2;
        const X = 1 << 3;
        const U = 1 << 4;
        const G = 1 << 5;
        const A = 1 << 6;
        const D = 1 << 7;
        const COW = 1 << 8;
    }
}

#[cfg(target_arch = "loongarch64")]
const LA_PTE_COW_BIT: usize = 1usize << 60;

#[derive(Copy, Clone)]
#[repr(C)]
pub struct PageTableEntry {
    bits: usize,
}

impl Debug for PageTableEntry {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        let ppn = self.ppn().0;
        let flags = self.flags().readable_flags();

        write!(f, "PTE {{ ppn: {:#x}, flags: {} }}", ppn, flags)
    }
}

impl PageTableEntry {
    ///Create a PTE from ppn
    #[cfg(target_arch = "riscv64")]
    pub fn new(ppn: PhysPageNum, flags: PTEFlags) -> Self {
        PageTableEntry {
            bits: ppn.0 << 10 | flags.bits() as usize,
        }
    }
    #[cfg(target_arch = "loongarch64")]
    pub fn new(ppn: PhysPageNum, flags: PTEFlags) -> Self {
        let mut bits = ppn.0 << PAGE_SIZE_BITS;
        if flags.contains(PTEFlags::V) {
            bits |= 1 << 0;
        }
        if flags.contains(PTEFlags::D) {
            bits |= 1 << 1;
        }
        if flags.contains(PTEFlags::U) {
            bits |= 3 << 2;
        }
        bits |= 1 << 4;
        if flags.contains(PTEFlags::G) {
            bits |= 1 << 6;
        }
        bits |= 1 << 7;
        if !flags.contains(PTEFlags::R) {
            bits |= 1usize << 61;
        }
        if !flags.contains(PTEFlags::X) {
            bits |= 1usize << 62;
        }
        if flags.contains(PTEFlags::W) {
            bits |= 1 << 8;
        }
        if flags.contains(PTEFlags::COW) {
            bits |= LA_PTE_COW_BIT;
        }
        PageTableEntry { bits }
    }
    /// Create a PTE from exist PTE, but clear PTE_W and set PTE_COW
    /// especially for COW
    pub fn from_pte_cow(pte: PageTableEntry) -> Self {
        let mut flags = pte.flags();
        flags.remove(PTEFlags::W);
        #[cfg(target_arch = "loongarch64")]
        flags.remove(PTEFlags::D);
        flags.insert(PTEFlags::COW);
        PageTableEntry::new(pte.ppn(), flags)
    }

